/** Built-in column presets for row layouts. */
export const PRESETS = Object.freeze([
    { label: '1 column',    icon: '█',       spans: [12] },
    { label: '2 equal',     icon: '▮▮',     spans: [6, 6] },
    { label: '2 left',      icon: '▮▯',     spans: [8, 4] },
    { label: '2 right',     icon: '▯▮',     spans: [4, 8] },
    { label: '3 equal',     icon: '▮▮▮',    spans: [4, 4, 4] },
    { label: '3 wide mid',  icon: '▯▮▯',    spans: [3, 6, 3] },
    { label: '4 equal',     icon: '▮▮▮▮',   spans: [3, 3, 3, 3] },
]);

// ═══════════════════════════════════════════════
// Block-type defaults
// ═══════════════════════════════════════════════

/**
 * Return per-type default property objects for new blocks.
 * @param {number} defaultGap — default gap value from config
 * @returns {Object<string,Object>}
 */
export function getBlockDefaults(defaultGap) {
    return {
        text:      { content: 'Text block — click to edit', style: { fontSize: '16px', color: 'var(--rui-text)' } },
        heading:   { content: 'Heading', style: { fontSize: '28px', fontWeight: '700', color: 'var(--rui-text)' } },
        image:     { content: '', style: { borderRadius: '6px', minHeight: '120px', background: 'var(--rui-bg-inset)' } },
        button:    { content: 'Button', style: { background: 'var(--rui-accent)', color: 'var(--rui-on-accent)', borderRadius: '6px', fontSize: '14px', fontWeight: '600', padding: '10px 24px', textAlign: 'center' } },
        divider:   { content: '', style: { borderTop: '1px solid var(--rui-border)', margin: '8px 0' } },
        spacer:    { content: '', style: { height: '40px' } },
        component: { content: '', componentName: '', pluginProps: {}, style: {} },
        html:      { content: '<p>Custom HTML</p>', style: {} },
        group:     { content: '', columns: [{ span: 6, blocks: [] }, { span: 6, blocks: [] }], gap: defaultGap, style: {} },
    };
}

