/**
 * @fileoverview GridEditor view — DOM construction for toolbar, rows, blocks,
 *               column grids, properties panels, preview mode, and export dialog.
 *
 * @module module/GridEditor/view
 */

import { PRESETS, PART } from './constants.js';
import { el, esc, matchPreset, findBlock } from './helpers.js';
import razyui from '../../index.js';
import Icons from '../Icons.js';
import {
    bindToolbar,
    bindBodyEvents,
    bindDelegatedEvents,
    bindRowHeader,
    bindBlockPropEvents,
    initColorPickers,
} from './events.js';
import { renderPluginProps } from '../_EditorProps.js';

// ═══════════════════════════════════════════════
// Initial DOM build
// ═══════════════════════════════════════════════

/**
 * Build the entire editor DOM structure.
 * @param {Object} ctx — editor context
 */
export function buildDOM(ctx) {
    const $container = razyui(ctx.container);
    $container.addClass('grid-editor ge-root');
    PART.ROOT.apply($container);
    $container.html('');

    // Toolbar
    ctx.toolbar = el('div', 'ge-toolbar');
    PART.TOOLBAR.apply(ctx.toolbar);
    ctx.toolbar.html(`
        <div class="ge-tb-group">
            <button class="ge-tb-btn" data-action="add-row" title="Add row (after selected)">${Icons.svg('plus', { size: 14, strokeWidth: 2 })} Row</button>
            <div class="ge-tb-dropdown">
                <button class="ge-tb-btn" data-action="add-row-preset" title="Add row with preset">${Icons.svg('chevron-down', { size: 14, strokeWidth: 2 })}</button>
                <div class="ge-tb-dropdown-menu">
                    ${PRESETS.map((p, i) => `<button class="ge-tb-dd-item" data-preset="${i}">${p.icon} ${p.label}</button>`).join('')}
                </div>
            </div>
            <button class="ge-tb-btn" data-action="add-col" title="Add column to selected row">${Icons.svg('plus', { size: 14, strokeWidth: 2 })} Col</button>
        </div>
        <div class="ge-tb-sep"></div>
        <div class="ge-tb-group">
            <button class="ge-tb-btn" data-action="add-text" title="Add text block">${Icons.svg('type', { size: 14, strokeWidth: 1.5 })} Text</button>
            <button class="ge-tb-btn" data-action="add-heading" title="Add heading">H Heading</button>
            <button class="ge-tb-btn" data-action="add-image" title="Add image">${Icons.svg('image', { size: 14, strokeWidth: 1.5 })} Image</button>
            <button class="ge-tb-btn" data-action="add-button" title="Add button">${Icons.svg('square-plus', { size: 14, strokeWidth: 1.5 })} Button</button>
            <button class="ge-tb-btn" data-action="add-divider" title="Add divider">${Icons.svg('minus', { size: 14, strokeWidth: 1.5 })} Divider</button>
            <button class="ge-tb-btn" data-action="add-spacer" title="Add spacer">${Icons.svg('square', { size: 14, strokeWidth: 1.5 })} Spacer</button>
            ${ctx.components.length ? `<button class="ge-tb-btn" data-action="add-component" title="Add component">${Icons.svg('grid', { size: 14, strokeWidth: 1.5 })} Component</button>` : ''}
        </div>
        <div class="ge-tb-sep"></div>
        <div class="ge-tb-group">
            <button class="ge-tb-btn" data-action="undo" title="Undo (Ctrl+Z)">${Icons.svg('rotate-ccw', { size: 14, strokeWidth: 1.8 })}</button>
            <button class="ge-tb-btn" data-action="redo" title="Redo (Ctrl+Y)">${Icons.svg('rotate-cw', { size: 14, strokeWidth: 1.8 })}</button>
        </div>
        <div class="ge-tb-sep"></div>
        <div class="ge-tb-group">
            <button class="ge-tb-btn" data-action="preview" title="Preview">${Icons.svg('eye', { size: 14, strokeWidth: 1.5 })} Preview</button>
            <button class="ge-tb-btn" data-action="export" title="Export JSON">${Icons.svg('download', { size: 14, strokeWidth: 1.5 })} Export</button>
        </div>
    `);
    $container.append(ctx.toolbar);

    // Body
    ctx.body = el('div', 'ge-body');
    PART.BODY.apply(ctx.body);

    // Rows container
    ctx.rowsContainer = el('div', 'ge-rows');
    PART.ROWS.apply(ctx.rowsContainer);
    ctx.body.append(ctx.rowsContainer);

    // Properties panel
    ctx.propPanel = el('div', 'ge-props');
    PART.PROPS.apply(ctx.propPanel);
    ctx.propPanel.html(`<div class="ge-panel-header">Properties</div><div class="ge-prop-body"><p class="ge-prop-empty">Select a block or row</p></div>`);

    ctx.body.append(ctx.propPanel);
    $container.append(ctx.body);

    // Events
    bindToolbar(ctx);
    bindBodyEvents(ctx);
    bindDelegatedEvents(ctx);
}

// ═══════════════════════════════════════════════
// Full render
// ═══════════════════════════════════════════════

/**
 * Clear and re-render all rows.
 * @param {Object} ctx
 */
export function fullRender(ctx) {
    ctx.rowsContainer.html('');
    ctx.rows.forEach((row, rowIdx) => renderRow(ctx, row, rowIdx));
    refreshProps(ctx);
}

// ═══════════════════════════════════════════════
// Row rendering
// ═══════════════════════════════════════════════

/**
 * Render a single row with its header, column grid, and blocks.
 * @param {Object} ctx
 * @param {Object} row
 * @param {number} rowIdx
 */
export function renderRow(ctx, row, rowIdx) {
    const rowEl = el('div', 'ge-row');
    PART.ROW.apply(rowEl);
    rowEl.data('geRow', row.id);
    rowEl.toggleClass('ge-row-selected', ctx.selectedRowId === row.id);

    if (!ctx.isPreview) {
        // Row header
        const header = el('div', 'ge-row-header');
        PART.ROW_HEADER.apply(header);
        header.html(`
            <span class="ge-row-drag" draggable="true" title="Drag to reorder">${Icons.svg('menu', { size: 14, strokeWidth: 1.5 })}</span>
            <span class="ge-row-label">Row ${rowIdx + 1}</span>
            <div class="ge-row-presets">
                ${PRESETS.map((p, i) => `<button class="ge-preset-btn ${matchPreset(row, p.spans) ? 'ge-preset-active' : ''}" data-preset="${i}" title="${p.label}">${p.icon}</button>`).join('')}
            </div>
            <div class="ge-row-actions">
                <button class="ge-row-act-btn" data-row-action="duplicate" title="Duplicate row">${Icons.svg('copy', { size: 12, strokeWidth: 1.5 })}</button>
                <button class="ge-row-act-btn" data-row-action="add-above" title="Add row above">${Icons.svg('arrow-up', { size: 12, strokeWidth: 1.8 })}</button>
                <button class="ge-row-act-btn" data-row-action="add-below" title="Add row below">${Icons.svg('arrow-down', { size: 12, strokeWidth: 1.8 })}</button>
                <button class="ge-row-act-btn ge-row-act-danger" data-row-action="remove" title="Remove row">${Icons.svg('x', { size: 12, strokeWidth: 2 })}</button>
            </div>
        `);
        rowEl.append(header);

        // Row header events
        bindRowHeader(ctx, header, row, rowIdx);
    }

    // Columns grid
    const grid = el('div', 'ge-columns');
    PART.COLUMNS.apply(grid);
    grid.css('grid-template-columns', row.columns.map(c => `${c.span}fr`).join(' '))
        .css('gap', row.gap + 'px');

    row.columns.forEach((col, colIdx) => {
        const colEl = el('div', 'ge-column');
        PART.COLUMN.apply(colEl);
        colEl.data('geRow', row.id);
        colEl.data('geCol', colIdx);

        col.blocks.forEach((block, blockIdx) => {
            const blockEl = renderBlock(ctx, block);
            blockEl.data('geBlockIdx', blockIdx);
            colEl.append(blockEl);
        });

        if (!ctx.isPreview) {
            // Empty column placeholder
            if (col.blocks.length === 0) {
                const placeholder = el('div', 'ge-column-placeholder');
                PART.COL_PH.apply(placeholder);
                placeholder.text('Drop content here');
                colEl.append(placeholder);
            }
        }

        grid.append(colEl);
    });

    rowEl.append(grid);
    ctx.rowsContainer.append(rowEl);
}

// ═══════════════════════════════════════════════
// Block rendering
// ═══════════════════════════════════════════════

/**
 * Render a single block element.
 * @param {Object} ctx
 * @param {Object} block
 * @returns {Elements}
 */
export function renderBlock(ctx, block) {
    const blockEl = el('div', 'ge-block');
    PART.BLOCK.apply(blockEl);
    blockEl.data('geBlock', block.id);
    blockEl.toggleClass('ge-block-selected', ctx.selectedBlockId === block.id);

    if (!ctx.isPreview) {
        // Block toolbar
        const toolbar = el('div', 'ge-block-toolbar');
        PART.BLOCK_TB.apply(toolbar);
        toolbar.html(`
            <span class="ge-block-type">${block.type}</span>
            <button class="ge-block-act" data-block-action="duplicate" title="Duplicate">${Icons.svg('copy', { size: 12, strokeWidth: 1.5 })}</button>
            <button class="ge-block-act ge-block-act-danger" data-block-action="remove" title="Remove">${Icons.svg('x', { size: 12, strokeWidth: 2 })}</button>
        `);
        blockEl.append(toolbar);
    }

    // Block content
    const content = el('div', 'ge-block-content');
    PART.BLOCK_CONTENT.apply(content);
    content.css(block.style || {});

    switch (block.type) {
        case 'text':
            content.addClass('ge-block-text');
            if (!ctx.isPreview) {
                content.attr('contenteditable', 'true');
                content.text(block.content);
            } else {
                content.text(block.content);
            }
            break;
        case 'heading':
            content.addClass('ge-block-heading');
            if (!ctx.isPreview) {
                content.attr('contenteditable', 'true');
                content.text(block.content);
            } else {
                content.text(block.content);
            }
            break;
        case 'image':
            content.addClass('ge-block-image');
            if (block.content) {
                const img = ctx.razyui.el('img', { src: block.content, alt: block.name || 'Image' });
                img.css({ width: '100%', display: 'block', 'border-radius': 'inherit' });
                content.append(img);
            } else {
                const placeholder = el('div', 'ge-img-placeholder');
                PART.IMG_PH.apply(placeholder);
                placeholder.html(Icons.svg('image', { size: 16, strokeWidth: 1.5 }) + ' <span>Click to set image URL</span>');
                content.append(placeholder);
            }
            break;
        case 'button':
            content.addClass('ge-block-button');
            const btn = el('span', 'ge-btn-inner');
            PART.BTN_INNER.apply(btn);
            btn.text(block.content || 'Button')
               .css(block.style || {});
            content.attr('style', '');
            content.append(btn);
            break;
        case 'divider':
            content.addClass('ge-block-divider');
            break;
        case 'spacer':
            content.addClass('ge-block-spacer');
            if (!ctx.isPreview) content.html(Icons.svg('square', { size: 14, strokeWidth: 1.5 }) + ' spacer');
            break;
        case 'component': {
            content.addClass('ge-block-component');
            const comp = ctx.components.find(c => c.name === block.componentName);
            if (comp && typeof comp.render === 'function') {
                try { comp.render(content[0], block); } catch (err) {
                    content.text(`⚠ Component error: ${err.message}`);
                }
            } else {
                content.html(`<div class="ge-component-placeholder">⧉ ${block.componentName || 'Component'}</div>`);
            }
            break;
        }
        case 'html':
            content.addClass('ge-block-html')
                   .html(block.content || '');
            break;
        case 'group':
            content.addClass('ge-block-group');
            renderGroup(ctx, content, block);
            break;
    }

    blockEl.append(content);

    return blockEl;
}

// ═══════════════════════════════════════════════
// Group rendering
// ═══════════════════════════════════════════════

/**
 * Render group block content (nested column layout).
 * @param {Object} ctx
 * @param {HTMLElement} container
 * @param {Object} groupBlock
 */
export function renderGroup(ctx, container, groupBlock) {
    const grid = el('div', 'ge-group-grid');
    PART.GROUP_GRID.apply(grid);
    grid.css('grid-template-columns', groupBlock.columns.map(c => `${c.span}fr`).join(' '))
        .css('gap', (groupBlock.gap || ctx.defaultGap) + 'px');

    groupBlock.columns.forEach((col, colIdx) => {
        const colEl = el('div', 'ge-group-column');
        PART.GROUP_COL.apply(colEl);
        colEl.data('geGroup', groupBlock.id);
        colEl.data('geGcol', colIdx);

        col.blocks.forEach(block => {
            const blockEl = renderBlock(ctx, block);
            colEl.append(blockEl);
        });

        if (!ctx.isPreview && col.blocks.length === 0) {
            const placeholder = el('div', 'ge-column-placeholder ge-group-placeholder');
            PART.COL_PH.apply(placeholder);
            PART.GROUP_PH.apply(placeholder);
            placeholder.text('Drop here');
            colEl.append(placeholder);
        }

        grid.append(colEl);
    });

    container.append(grid);
}

// ═══════════════════════════════════════════════
// Selection
// ═══════════════════════════════════════════════

/**
 * Select a block by ID.
 * @param {Object} ctx
 * @param {string} blockId
 */
export function selectBlock(ctx, blockId) {
    ctx.selectedBlockId = blockId;
    ctx.selectedRowId = null;
    ctx.rowsContainer.find('.ge-block-selected').removeClass('ge-block-selected');
    ctx.rowsContainer.find('.ge-row-selected').removeClass('ge-row-selected');
    ctx.rowsContainer.find(`[data-ge-block="${blockId}"]`).addClass('ge-block-selected');
    refreshProps(ctx);
}

/**
 * Select a row by ID.
 * @param {Object} ctx
 * @param {string} rowId
 */
export function selectRow(ctx, rowId) {
    ctx.selectedRowId = rowId;
    ctx.selectedBlockId = null;
    ctx.rowsContainer.find('.ge-block-selected').removeClass('ge-block-selected');
    ctx.rowsContainer.find('.ge-row-selected').removeClass('ge-row-selected');
    ctx.rowsContainer.find(`[data-ge-row="${rowId}"]`).addClass('ge-row-selected');
    refreshProps(ctx);
}

/**
 * Clear all selection.
 * @param {Object} ctx
 */
export function clearSelection(ctx) {
    ctx.selectedBlockId = null;
    ctx.selectedRowId = null;
    ctx.rowsContainer.find('.ge-block-selected, .ge-row-selected').removeClass('ge-block-selected').removeClass('ge-row-selected');
    refreshProps(ctx);
}

// ═══════════════════════════════════════════════
// Properties panel
// ═══════════════════════════════════════════════

/**
 * Refresh the properties panel based on current selection.
 * @param {Object} ctx
 */
export function refreshProps(ctx) {
    const body = ctx.propPanel.find('.ge-prop-body');

    // Row selected
    if (ctx.selectedRowId) {
        const row = ctx.rows.find(r => r.id === ctx.selectedRowId);
        if (!row) { body.html('<p class="ge-prop-empty">Row not found</p>'); return; }
        renderRowProps(ctx, body, row);
        return;
    }

    // Block selected
    if (ctx.selectedBlockId) {
        const result = findBlock(ctx.selectedBlockId, ctx.rows);
        if (!result) { body.html('<p class="ge-prop-empty">Block not found</p>'); return; }
        renderBlockProps(ctx, body, result.block);
        return;
    }

    body.html('<p class="ge-prop-empty">Select a block or row</p>');
}

/**
 * Render properties panel for a selected row.
 * @param {Object} ctx
 * @param {HTMLElement} body
 * @param {Object} row
 */
export function renderRowProps(ctx, body, row) {
    const colSpans = row.columns.map(c => c.span).join(' / ');
    body.html(`
        <div class="ge-prop-section-title">Row Settings</div>
        <div class="ge-prop-section">
            <label class="ge-prop-label">Columns (${row.columns.length})</label>
            <div class="ge-prop-preset-grid">
                ${PRESETS.map((p, i) => `<button class="ge-preset-chip ${matchPreset(row, p.spans) ? 'ge-preset-chip-active' : ''}" data-preset="${i}">${p.icon} ${p.label}</button>`).join('')}
            </div>
        </div>
        <div class="ge-prop-section">
            <label class="ge-prop-label">Custom Spans (${ctx.maxColumns}-col grid)</label>
            <input class="ge-prop-input ge-prop-full" type="text" data-row-prop="spans" value="${colSpans}" placeholder="e.g. 4 / 8  or  3 / 3 / 6">
        </div>
        <div class="ge-prop-section">
            <label class="ge-prop-label">Gap (px)</label>
            <input class="ge-prop-input" type="number" data-row-prop="gap" value="${row.gap}" min="0" max="100">
        </div>
    `);

}

/**
 * Render properties panel for a selected block.
 * @param {Object} ctx
 * @param {HTMLElement} body
 * @param {Object} block
 */
export function renderBlockProps(ctx, body, block) {
    body.html(`
        <div class="ge-prop-section-title">${block.type.charAt(0).toUpperCase() + block.type.slice(1)} Block</div>
        <div class="ge-prop-section">
            <label class="ge-prop-label">Name</label>
            <input class="ge-prop-input ge-prop-full" type="text" data-block-prop="name" value="${esc(block.name)}">
        </div>
        ${blockTypeProps(ctx, block)}
        <div class="ge-prop-divider"></div>
        <div class="ge-prop-section-title">Style</div>
        ${blockStyleProps(ctx, block)}
    `);
    bindBlockPropEvents(ctx, body, block);
    initColorPickers(ctx, body, block);
}

/**
 * Generate block type-specific property HTML.
 * @param {Object} ctx
 * @param {Object} block
 * @returns {string}
 */
export function blockTypeProps(ctx, block) {
    let html = '';
    switch (block.type) {
        case 'text':
        case 'heading':
            html += `<div class="ge-prop-section">
                <label class="ge-prop-label">Content</label>
                <textarea class="ge-prop-input ge-prop-full ge-prop-textarea" data-block-prop="content" rows="3">${esc(block.content)}</textarea>
            </div>`;
            break;
        case 'image':
            html += `<div class="ge-prop-section">
                <label class="ge-prop-label">Image URL</label>
                <input class="ge-prop-input ge-prop-full" type="text" data-block-prop="content" value="${esc(block.content)}" placeholder="https://...">
            </div>`;
            break;
        case 'button':
            html += `<div class="ge-prop-section">
                <label class="ge-prop-label">Label</label>
                <input class="ge-prop-input ge-prop-full" type="text" data-block-prop="content" value="${esc(block.content)}">
            </div>`;
            break;
        case 'spacer':
            html += `<div class="ge-prop-section">
                <label class="ge-prop-label">Height</label>
                <input class="ge-prop-input" type="text" data-block-style="height" value="${esc(block.style?.height || '40px')}">
            </div>`;
            break;
        case 'component':
            html += `<div class="ge-prop-section">
                <label class="ge-prop-label">Component</label>
                <select class="ge-prop-input" data-block-prop="componentName">
                    <option value="">— Select —</option>
                    ${ctx.components.map(c => `<option value="${c.name}" ${block.componentName === c.name ? 'selected' : ''}>${c.name}</option>`).join('')}
                </select>
            </div>`;
            // Render plugin-defined properties
            if (block.componentName) {
                const comp = ctx.components.find(c => c.name === block.componentName);
                if (comp?.properties?.length) {
                    html += '<div class="ge-prop-divider"></div><div class="ge-prop-section-title">Component Properties</div>';
                    if (!block.pluginProps) block.pluginProps = {};
                    html += renderPluginProps(comp.properties, block.pluginProps, 'ge');
                }
            }
            break;
        case 'html':
            html += `<div class="ge-prop-section">
                <label class="ge-prop-label">HTML</label>
                <textarea class="ge-prop-input ge-prop-full ge-prop-textarea ge-prop-mono" data-block-prop="content" rows="5">${esc(block.content)}</textarea>
            </div>`;
            break;
        case 'group': {
            const colSpans = block.columns.map(c => c.span).join(' / ');
            html += `<div class="ge-prop-section">
                <label class="ge-prop-label">Group Columns</label>
                <input class="ge-prop-input ge-prop-full" type="text" data-block-prop="group-spans" value="${colSpans}" placeholder="e.g. 6 / 6">
            </div>
            <div class="ge-prop-section">
                <label class="ge-prop-label">Group Gap (px)</label>
                <input class="ge-prop-input" type="number" data-block-prop="group-gap" value="${block.gap || ctx.defaultGap}" min="0">
            </div>`;
            break;
        }
    }
    return html;
}

/**
 * Generate style property HTML for a block.
 * @param {Object} ctx
 * @param {Object} block
 * @returns {string}
 */
export function blockStyleProps(ctx, block) {
    let html = '';
    if (['text', 'heading', 'button'].includes(block.type)) {
        html += `
            <div class="ge-prop-section">
                <label class="ge-prop-label">Font Size</label>
                <input class="ge-prop-input" type="text" data-block-style="fontSize" value="${esc(block.style?.fontSize || '')}">
            </div>
            <div class="ge-prop-section">
                <label class="ge-prop-label">Font Weight</label>
                <input class="ge-prop-input" type="text" data-block-style="fontWeight" value="${esc(block.style?.fontWeight || '')}">
            </div>
            <div class="ge-prop-section">
                <label class="ge-prop-label">Color</label>
                <div class="ge-prop-color-wrap">
                    <span class="ge-prop-color-swatch" data-color-for="color" style="background:${esc(block.style?.color || 'transparent')}"></span>
                    <input class="ge-prop-input" type="text" data-block-style="color" value="${esc(block.style?.color || '')}">
                </div>
            </div>
            <div class="ge-prop-section">
                <label class="ge-prop-label">Text Align</label>
                <select class="ge-prop-input" data-block-style="textAlign">
                    <option value="" ${!block.style?.textAlign ? 'selected' : ''}>—</option>
                    <option value="left" ${block.style?.textAlign === 'left' ? 'selected' : ''}>Left</option>
                    <option value="center" ${block.style?.textAlign === 'center' ? 'selected' : ''}>Center</option>
                    <option value="right" ${block.style?.textAlign === 'right' ? 'selected' : ''}>Right</option>
                </select>
            </div>`;
    }
    html += `
        <div class="ge-prop-section">
            <label class="ge-prop-label">Background</label>
            <div class="ge-prop-color-wrap">
                <span class="ge-prop-color-swatch" data-color-for="background" style="background:${esc(block.style?.background || 'transparent')}"></span>
                <input class="ge-prop-input ge-prop-full" type="text" data-block-style="background" value="${esc(block.style?.background || '')}">
            </div>
        </div>
        <div class="ge-prop-section">
            <label class="ge-prop-label">Border Radius</label>
            <input class="ge-prop-input" type="text" data-block-style="borderRadius" value="${esc(block.style?.borderRadius || '')}">
        </div>
        <div class="ge-prop-section">
            <label class="ge-prop-label">Padding</label>
            <input class="ge-prop-input" type="text" data-block-style="padding" value="${esc(block.style?.padding || '')}">
        </div>
        <div class="ge-prop-section">
            <label class="ge-prop-label">Margin</label>
            <input class="ge-prop-input" type="text" data-block-style="margin" value="${esc(block.style?.margin || '')}">
        </div>`;
    return html;
}

// ═══════════════════════════════════════════════
// Preview / Export
// ═══════════════════════════════════════════════

/**
 * Toggle preview mode.
 * @param {Object} ctx
 */
export function togglePreview(ctx) {
    ctx.isPreview = !ctx.isPreview;
    const $container = razyui(ctx.container);
    $container.toggleClass('ge-preview', ctx.isPreview);
    // Show / hide floating exit-preview button
    let $exitBtn = $container.find('.ge-exit-preview');
    if (ctx.isPreview) {
        if (!$exitBtn.length) {
            $exitBtn = el('button', 'ge-exit-preview');
            PART.EXIT_PREVIEW.apply($exitBtn);
            $exitBtn.html(Icons.svg('x', { size: 14, strokeWidth: 2 }) + ' Exit Preview');
            $container.append($exitBtn);
        }
        $exitBtn.css('display', '');
    } else {
        if ($exitBtn.length) $exitBtn.css('display', 'none');
    }
    fullRender(ctx);
}

/**
 * Show the export JSON popup.
 * @param {Object} ctx
 */
export function showExportPopup(ctx) {
    const data = { rows: JSON.parse(JSON.stringify(ctx.rows)) };
    const json = JSON.stringify(data, null, 2);

    // Remove existing export popup
    const $container = razyui(ctx.container);
    const existingPopup = $container.find('.ge-export-popup');
    if (existingPopup.length) existingPopup[0].remove();

    const overlay = el('div', 'ge-export-popup');
    PART.EXPORT_POPUP.apply(overlay);
    overlay.html(`
        <div class="ge-export-dialog">
            <div class="ge-export-header">
                <span class="ge-export-title">Export JSON</span>
                <button class="ge-export-close" title="Close">${Icons.svg('x', { size: 14, strokeWidth: 2 })}</button>
            </div>
            <textarea class="ge-export-code" readonly spellcheck="false"></textarea>
            <div class="ge-export-actions">
                <button class="ge-export-btn ge-export-copy">${Icons.svg('clipboard', { size: 14, strokeWidth: 1.5 })} Copy</button>
                <button class="ge-export-btn ge-export-download">${Icons.svg('download', { size: 14, strokeWidth: 1.5 })} Download</button>
            </div>
        </div>
    `);

    // Set textarea value (avoids HTML escaping issues)
    overlay.find('.ge-export-code').val(json);

    // Close
    overlay.find('.ge-export-close').on('click', () => overlay[0].remove());
    overlay.on('click', (e) => { if (e.target === overlay[0]) overlay[0].remove(); });

    // Copy
    overlay.find('.ge-export-copy').on('click', () => {
        navigator.clipboard?.writeText(json);
        const btn = overlay.find('.ge-export-copy');
        btn.html(Icons.svg('check', { size: 14, strokeWidth: 2 }) + ' Copied!');
        setTimeout(() => btn.html(Icons.svg('clipboard', { size: 14, strokeWidth: 1.5 }) + ' Copy'), 1500);
    });

    // Download
    overlay.find('.ge-export-download').on('click', () => {
        const blob = new Blob([json], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = ctx.razyui.el('a', { href: url, download: 'grid-layout.json' });
        a.trigger('click');
        URL.revokeObjectURL(url);
    });

    $container.append(overlay);
    const ta = overlay.find('.ge-export-code');
    ta.focus();
    ta[0].select();
}

// ═══════════════════════════════════════════════
// Toolbar component button management
// ═══════════════════════════════════════════════

/**
 * Rebuild the component button visibility in the toolbar.
 * @param {Object} ctx
 */
export function rebuildToolbarComponents(ctx) {
    // Update the component button visibility in toolbar
    const insertGroup = ctx.toolbar.find('.ge-tb-group:nth-child(3)');
    let compBtn = ctx.toolbar.find('[data-action="add-component"]');
    if (ctx.components.length && !compBtn.length) {
        compBtn = el('button', 'ge-tb-btn');
        compBtn.data('action', 'add-component');
        compBtn.attr('title', 'Add component');
        compBtn.text('⧉ Component');
        insertGroup.append(compBtn);
    } else if (!ctx.components.length && compBtn.length) {
        compBtn[0].remove();
    }
}
